var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`예전부터 친척 분들이 말씀하셨어요.`,JPN:`以前から親戚にこう言われていました。`,ENG:`My relatives always told me`,TWN:`以前親戚跟我說過。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`저는...... 태어날 때부터 다른 사람들과 많이 달랐다고요.`,JPN:`私は……生まれた時から普通じゃなかったって。`,ENG:`that I... I was different from others since I was born.`,TWN:`我……從出生開始就和別人不一樣。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`이진 언니는 아니라고 말해 줬지만...... 혹시라도, 어르신들 말씀이 맞다면......`,JPN:`ホノカさんはそれは違うと言ってくださいましたが……万が一、親戚の言ってることが合ってるなら……`,ENG:`Lee Jin said that wasn't true, but what if they were right?`,TWN:`雖然李珍姐姐說不是那樣的……但如果，長輩們說得是正確的……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`그래서, 사장님마저 저를 싫어하시게 되면 어떡해야 할까......`,JPN:`それで、社長も私のことを嫌いになってしまったらどうしようって……`,ENG:`I was afraid...`,TWN:`那麼連老闆都討厭我的話，我該怎麼辦……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`그동안, 많이 무서웠어요.`,JPN:`今までそんな不安を抱いていました。`,ENG:`that I might repel you, like I did my relatives.`,TWN:`這段時間，我真的很害怕。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`......이 계약서에 서명하면, 더는 무섭지 않겠죠?`,JPN:`……この契約書にサインすれば、そんな不安はなくなるんでしょうね。`,ENG:`I won't have to worry about that anymore once I sign this contract, right?`,TWN:`……如果在這份契約書上簽名，我就不用再害怕了吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`고마워요, 사장님. 저를 싫어하지 않아 주셔서.`,JPN:`ありがとうございます、社長。私を嫌いにならないでいてくださって。`,ENG:`Thank you, Boss, for not hating me.`,TWN:`謝謝你，老闆。謝謝你沒有討厭我。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JIA_ALPHA_RACING_NULL`,text:{KOREA:`이제부터는 저도...... 사장님에 대한 마음을 솔직하게 표현할 수 있도록 해 볼게요.`,JPN:`これからは私も……社長への気持ちを素直に表現できるように頑張ります。`,ENG:`From now on, I'll try my best to be more honest with you.`,TWN:`從現在開始，我也……會試著誠實表達自己對老闆的心意。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JIA_ALPHA_RACING_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};